import { LightboxProps } from "../../index.js";

export const defaultZoomProps = {
  minZoom: 1,
  maxZoomPixelRatio: 1,
  zoomInMultiplier: 2,
  doubleTapDelay: 300,
  doubleClickDelay: 500,
  doubleClickMaxStops: 2,
  keyboardMoveDistance: 50,
  wheelZoomDistanceFactor: 100,
  pinchZoomDistanceFactor: 100,
  pinchZoomV4: false,
  scrollToZoom: false,
};

function validateMinZoom(minZoom: number) {
  return Math.min(Math.max(minZoom, Number.EPSILON), 1);
}

export function resolveZoomProps(zoom: LightboxProps["zoom"]) {
  const { minZoom, ...rest } = { ...defaultZoomProps, ...zoom };
  return { minZoom: validateMinZoom(minZoom), ...rest };
}

import * as React from "react";

import { addToolbarButton, createModule, isImageSlide, Plugin, PLUGIN_ZOOM } from "../../index.js";
import { resolveZoomProps } from "./props.js";
import { ZoomContextProvider } from "./ZoomController.js";
import { ZoomToolbarControl } from "./ZoomToolbarControl.js";
import { ZoomWrapper } from "./ZoomWrapper.js";

/** Zoom plugin */
export const Zoom: Plugin = ({ augment, addModule }) => {
  augment(({ zoom: zoomProps, toolbar, render, controller, ...restProps }) => {
    const zoom = resolveZoomProps(zoomProps);
    return {
      zoom,
      toolbar: addToolbarButton(toolbar, PLUGIN_ZOOM, <ZoomToolbarControl />),
      render: {
        ...render,
        slide: (props) =>
          isImageSlide(props.slide) ? <ZoomWrapper render={render} {...props} /> : render.slide?.(props),
      },
      controller: { ...controller, preventDefaultWheelY: zoom.scrollToZoom },
      ...restProps,
    };
  });

  addModule(createModule(PLUGIN_ZOOM, ZoomContextProvider));
};

import {
  ContainerRect,
  isImageFitCover,
  isImageSlide,
  round,
  useLightboxProps,
  useLightboxState,
} from "../../../index.js";
import { useZoomProps } from "./useZoomProps.js";

export function useZoomImageRect(slideRect: ContainerRect, imageDimensions?: ContainerRect) {
  let imageRect: ContainerRect = { width: 0, height: 0 };
  let maxImageRect: ContainerRect = { width: 0, height: 0 };

  const { currentSlide } = useLightboxState();
  const { imageFit } = useLightboxProps().carousel;
  const { maxZoomPixelRatio } = useZoomProps();

  if (slideRect && currentSlide) {
    const slide = { ...currentSlide, ...imageDimensions };
    if (isImageSlide(slide)) {
      const cover = isImageFitCover(slide, imageFit);

      const width = Math.max(...(slide.srcSet?.map((x) => x.width) || []).concat(slide.width ? [slide.width] : []));

      const height = Math.max(...(slide.srcSet?.map((x) => x.height) || []).concat(slide.height ? [slide.height] : []));

      if (width > 0 && height > 0 && slideRect.width > 0 && slideRect.height > 0) {
        maxImageRect = cover
          ? {
              width: Math.round(Math.min(width, (slideRect.width / slideRect.height) * height)),
              height: Math.round(Math.min(height, (slideRect.height / slideRect.width) * width)),
            }
          : { width, height };

        maxImageRect = {
          width: maxImageRect.width * maxZoomPixelRatio,
          height: maxImageRect.height * maxZoomPixelRatio,
        };

        imageRect = cover
          ? {
              width: Math.min(slideRect.width, maxImageRect.width, width),
              height: Math.min(slideRect.height, maxImageRect.height, height),
            }
          : {
              width: Math.round(Math.min(slideRect.width, (slideRect.height / height) * width, width)),
              height: Math.round(Math.min(slideRect.height, (slideRect.width / width) * height, height)),
            };
      }
    }
  }

  const maxZoom = imageRect.width ? Math.max(round(maxImageRect.width / imageRect.width, 5), 1) : 1;

  return { imageRect, maxZoom };
}

import * as React from "react";

import {
  CLASS_FLEX_CENTER,
  CLASS_FULLSIZE,
  CLASS_SLIDE_WRAPPER,
  CLASS_SLIDE_WRAPPER_INTERACTIVE,
  clsx,
  ContainerRect,
  cssClass,
  ImageSlide,
  isImageSlide,
  LightboxProps,
  RenderSlideProps,
  useLayoutEffect,
  useLightboxProps,
  useLightboxState,
} from "../../index.js";
import { useZoom } from "./ZoomController.js";
import { isResponsiveImageSlide, ResponsiveImage } from "./ResponsiveImage.js";

// using the non-augmented `render` here
export type ZoomWrapperProps = Pick<LightboxProps, "render"> & RenderSlideProps;

/** Zoom wrapper */
export function ZoomWrapper({ render, slide, offset, rect }: ZoomWrapperProps) {
  const [imageDimensions, setImageDimensions] = React.useState<ContainerRect>();
  const zoomWrapperRef = React.useRef<HTMLDivElement>(null);

  const { zoom, maxZoom, offsetX, offsetY, setZoomWrapper } = useZoom();
  const interactive = zoom > 1;

  const { carousel, on } = useLightboxProps();
  const { currentIndex } = useLightboxState();

  useLayoutEffect(() => {
    if (offset === 0) {
      setZoomWrapper({ zoomWrapperRef, imageDimensions });
      return () => setZoomWrapper(undefined);
    }
    return () => {};
  }, [offset, imageDimensions, setZoomWrapper]);

  let rendered = render.slide?.({ slide, offset, rect, zoom, maxZoom });

  if (!rendered && isImageSlide(slide)) {
    const slideProps = {
      slide,
      offset,
      rect,
      render,
      imageFit: carousel.imageFit,
      imageProps: carousel.imageProps,
      onClick: offset === 0 ? () => on.click?.({ index: currentIndex }) : undefined,
    };

    rendered = isResponsiveImageSlide(slide) ? (
      <ResponsiveImage
        {...slideProps}
        slide={slide}
        interactive={interactive}
        rect={offset === 0 ? { width: rect.width * zoom, height: rect.height * zoom } : rect}
      />
    ) : (
      <ImageSlide
        onLoad={(img) => setImageDimensions({ width: img.naturalWidth, height: img.naturalHeight })}
        {...slideProps}
      />
    );
  }

  if (!rendered) return null;

  return (
    <div
      ref={zoomWrapperRef}
      className={clsx(
        cssClass(CLASS_FULLSIZE),
        cssClass(CLASS_FLEX_CENTER),
        cssClass(CLASS_SLIDE_WRAPPER),
        interactive && cssClass(CLASS_SLIDE_WRAPPER_INTERACTIVE),
      )}
      style={
        offset === 0 ? { transform: `scale(${zoom}) translateX(${offsetX}px) translateY(${offsetY}px)` } : undefined
      }
    >
      {rendered}
    </div>
  );
}

